// ============================================================
//  1. PROCESAR INSPECCIÓN — llamado desde AppSheet Bot
//     Call a Script → Function: procesarInspeccion
//     Parámetro:     idInspeccion = <<IdInspeccionesPPR>>
// ============================================================
function procesarInspeccion(idInspeccion) {
  idInspeccion = String(idInspeccion).trim();

  var ss        = SpreadsheetApp.openById(SHEET_ID);
  var wsOrigen  = ss.getSheetByName(SHEET_ORIGEN);
  var wsDestino = ss.getSheetByName(SHEET_DESTINO);

  if (!wsOrigen)  throw new Error("Hoja no encontrada: " + SHEET_ORIGEN);
  if (!wsDestino) throw new Error("Hoja no encontrada: " + SHEET_DESTINO);

  var datosOrigen = wsOrigen.getDataRange().getValues();
  var filaData = null;
  for (var i = 1; i < datosOrigen.length; i++) {
    if (String(datosOrigen[i][1]).trim() === idInspeccion) {
      filaData = datosOrigen[i];
      break;
    }
  }
  if (!filaData) { Logger.log("Inspección no encontrada: " + idInspeccion); return; }

  var fecha = filaData[5];
  var area  = filaData[2];

  // Borrar solo Pendiente / En Proceso (conservar Cerrado)
  var dest = wsDestino.getDataRange().getValues();
  for (var j = dest.length - 1; j >= 1; j--) {
    if (String(dest[j][11]).trim() === idInspeccion) {
      if (String(dest[j][10]).trim() !== "Cerrado") wsDestino.deleteRow(j + 1);
    }
  }

  var dest2 = wsDestino.getDataRange().getValues();
  var maxID = 0;
  for (var k = 1; k < dest2.length; k++) {
    var n = parseInt(dest2[k][0]);
    if (!isNaN(n) && n > maxID) maxID = n;
  }

  var agregados = 0;
  for (var p = 0; p < PUNTOS_INSPECCION.length; p++) {
    var pto    = PUNTOS_INSPECCION[p];
    var resp   = String(filaData[pto[0]-1] || "").trim();
    if (resp === VALOR_NO_CUMPLE) {
      maxID++;
      wsDestino.appendRow([
        maxID, fecha, area, pto[3],
        filaData[pto[1]-1] || "",
        filaData[pto[2]-1] || "",
        "", "", "", "",
        "Pendiente",
        idInspeccion
      ]);
      agregados++;
    }
  }
  Logger.log("Inspección " + idInspeccion + ": " + agregados + " hallazgo(s) generados.");
}

// ============================================================
//  2. doGet — el portal HTML solicita datos
//     Acciones soportadas via ?action=XXXX :
//       login          → valida usuario y contraseña
//       getHallazgos   → devuelve hallazgos del área del usuario
// ============================================================
function doGet(e) {
  var action = e.parameter.action || "";
  var result;

  try {
    if (action === "login") {
      result = validarLogin(e.parameter.usuario, e.parameter.pass);

    } else if (action === "getHallazgos") {
      result = getHallazgos(e.parameter.usuario, e.parameter.token);

    } else {
      result = { ok: false, error: "Acción no reconocida" };
    }
  } catch(err) {
    result = { ok: false, error: err.message };
  }

  return ContentService
    .createTextOutput(JSON.stringify(result))
    .setMimeType(ContentService.MimeType.JSON);
}

// ============================================================
//  3. doPost — el portal HTML guarda cambios en SeguimientoACC
//     Body JSON: { token, usuario, rowIndex, accion, responsable,
//                  fechaCompromiso, evidenciaCierre, estatus }
// ============================================================
function doPost(e) {
  var result;
  try {
    var data = JSON.parse(e.postData.contents);

    // Verificar token de sesión antes de escribir
    if (!tokenValido(data.usuario, data.token)) {
      return jsonResponse({ ok: false, error: "Sesión inválida, vuelve a iniciar sesión." });
    }

    actualizarACC(
      data.rowIndex,
      data.accion          || "",
      data.responsable     || "",
      data.fechaCompromiso || "",
      data.evidenciaCierre || "",
      data.estatus         || "Pendiente"
    );
    result = { ok: true };
  } catch(err) {
    result = { ok: false, error: err.message };
  }
  return jsonResponse(result);
}

// ============================================================
//  FUNCIÓN PRINCIPAL DE ESCRITURA
//  Actualiza columnas G, H, I, J, K de SeguimientoACC
// ============================================================
function actualizarACC(rowIndex, accion, responsable, fechaCompromiso, evidenciaCierre, estatus) {
  var ss = SpreadsheetApp.openById(SHEET_ID);
  var ws = ss.getSheetByName(SHEET_DESTINO);
  if (!ws) throw new Error("Hoja no encontrada: " + SHEET_DESTINO);

  var fila = parseInt(rowIndex);
  if (isNaN(fila) || fila < 2) throw new Error("rowIndex inválido: " + rowIndex);

  // Solo se permite editar si el estatus actual NO es Cerrado
  var estatusActual = ws.getRange(fila, 11).getValue();
  if (String(estatusActual).trim() === "Cerrado") {
    throw new Error("Este hallazgo ya está cerrado y no puede modificarse.");
  }

  ws.getRange(fila, 7).setValue(accion);           // G - Acciones Correctivas
  ws.getRange(fila, 8).setValue(responsable);       // H - Responsable
  ws.getRange(fila, 9).setValue(fechaCompromiso);   // I - Fecha compromiso
  ws.getRange(fila, 10).setValue(evidenciaCierre);  // J - Evidencia del cierre
  ws.getRange(fila, 11).setValue(estatus);          // K - Estatus

  Logger.log("Fila " + fila + " actualizada → Estatus: " + estatus);
}

// ============================================================
//  AUTENTICACIÓN — usuarios en hoja UsuariosPortal
//  Columnas: A=Usuario  B=Contraseña  C=Área  D=Activo(TRUE/FALSE)
// ============================================================

// Genera un token simple basado en usuario + fecha del día
// (no es JWT pero es suficiente para uso interno sin HTTPS complejo)
function generarToken(usuario) {
  var hoy = Utilities.formatDate(new Date(), "America/El_Salvador", "yyyyMMdd");
  return Utilities.base64Encode(usuario + "|" + hoy + "|acc_bpm");
}

function tokenValido(usuario, token) {
  return token === generarToken(usuario);
}

function validarLogin(usuario, pass) {
  if (!usuario || !pass) return { ok: false, error: "Usuario y contraseña requeridos." };

  var ss = SpreadsheetApp.openById(SHEET_ID);
  var ws = ss.getSheetByName(SHEET_USUARIOS);
  if (!ws) return { ok: false, error: "Hoja UsuariosPortal no encontrada." };

  var datos = ws.getDataRange().getValues();
  for (var i = 1; i < datos.length; i++) {
    var uUser   = String(datos[i][0]).trim().toLowerCase();
    var uPass   = String(datos[i][1]).trim();
    var uArea   = String(datos[i][2]).trim();
    var uActivo = String(datos[i][3]).trim().toUpperCase();

    if (uUser === usuario.toLowerCase() && uPass === pass) {
      if (uActivo !== "TRUE") {
        return { ok: false, error: "Usuario inactivo. Contacta al administrador." };
      }
      return {
        ok:      true,
        usuario: uUser,
        area:    uArea,
        token:   generarToken(uUser),
        nombre:  String(datos[i][4] || uUser)   // col E opcional: nombre completo
      };
    }
  }
  return { ok: false, error: "Usuario o contraseña incorrectos." };
}

function getHallazgos(usuario, token) {
  if (!tokenValido(usuario, token)) {
    return { ok: false, error: "Sesión expirada, vuelve a iniciar sesión." };
  }

  // Obtener área del usuario
  var ss      = SpreadsheetApp.openById(SHEET_ID);
  var wsUsers = ss.getSheetByName(SHEET_USUARIOS);
  var usuarios = wsUsers.getDataRange().getValues();
  var area = "";
  for (var u = 1; u < usuarios.length; u++) {
    if (String(usuarios[u][0]).trim().toLowerCase() === usuario.toLowerCase()) {
      area = String(usuarios[u][2]).trim();
      break;
    }
  }
  if (!area) return { ok: false, error: "No se encontró el área del usuario." };

  var wsDest = ss.getSheetByName(SHEET_DESTINO);
  var datos  = wsDest.getDataRange().getValues();
  var filas  = [];

  for (var i = 1; i < datos.length; i++) {
    if (String(datos[i][2]).trim() === area) {
      filas.push({
        rowIndex:      i + 1,        // fila real en Sheet
        idacc:         datos[i][0],
        fecha:         datos[i][1] ? Utilities.formatDate(new Date(datos[i][1]), "America/El_Salvador", "dd/MM/yyyy") : "",
        area:          datos[i][2],
        punto:         datos[i][3],
        descripcion:   datos[i][4],
        foto:          datos[i][5],
        accion:        datos[i][6],
        responsable:   datos[i][7],
        fechaComp:     datos[i][8] ? Utilities.formatDate(new Date(datos[i][8]), "America/El_Salvador", "dd/MM/yyyy") : "",
        evidenciaCierre: datos[i][9],
        estatus:       datos[i][10] || "Pendiente",
        idOrigen:      datos[i][11]
      });
    }
  }

  return { ok: true, area: area, hallazgos: filas };
}

function jsonResponse(obj) {
  return ContentService
    .createTextOutput(JSON.stringify(obj))
    .setMimeType(ContentService.MimeType.JSON);
}

